                .drawBehind {
                    val stroke = 2.dp.toPx()
                    val s = this.size
                    drawLine(Color.White.copy(alpha = 0.2f), Offset(s.width, s.height), Offset(0f, s.height), stroke)
                    drawLine(Color.White.copy(alpha = 0.2f), Offset(s.width, s.height), Offset(s.width, 0f), stroke)
                }
        )
    }
}
